LOCK TABLES `ai_message` WRITE;
/*!40000 ALTER TABLE `ai_message` DISABLE KEYS */;
INSERT INTO `ai_message` VALUES (2038235767856975873,2038235767332687874,'user','给我一版 3 天游轻松路线，早中晚各 1 个景点\n\n【输出要求】请输出可保存的结构化行程 JSON，字段必须包含 destination、days、budget、theme、dailyPlans、totalEstimatedCost、tips。dailyPlans.activities 中每个景点必须包含：time（只允许 morning/noon/evening 三种）、name、description、type、location.address、estimatedCost、imageUrl。',NULL,NULL,'2026-03-29 20:44:10',0),(2038235927630598146,2038235767332687874,'assistant','观察: 为您规划了3天2晚的轻松游行程，覆盖杭州主要景点，早中晚各安排1个景点，含住宿与餐饮建议，预算约2000元，适合休闲度假。\n\n```json\n{\n  \"destination\": \"杭州\",\n  \"days\": 3,\n  \"budget\": 2000,\n  \"theme\": \"轻松休闲游\",\n  \"dailyPlans\": [\n    {\n      \"day\": 1,\n      \"date\": \"2024-01-01\",\n      \"activities\": [\n        {\n          \"time\": \"morning\",\n          \"name\": \"西湖断桥\",\n          \"type\": \"attraction\",\n          \"description\": \"漫步西湖，欣赏断桥残雪美景，体验江南水乡风情\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1588045538788-6c2c8b4e4f1a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市西湖区断桥路\"\n          },\n          \"estimatedCost\": 0,\n          \"tips\": [\"建议早上8点前到达，避开人流\", \"可租借共享单车环湖游览\"]\n        },\n        {\n          \"time\": \"noon\",\n          \"name\": \"楼外楼\",\n          \"type\": \"meal\",\n          \"description\": \"品尝杭州地道杭帮菜，推荐西湖醋鱼、龙井虾仁\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市上城区湖滨路18号\"\n          },\n          \"estimatedCost\": 200,\n          \"tips\": [\"提前预订，避免排队\", \"可选择湖景包厢\"]\n        },\n        {\n          \"time\": \"evening\",\n          \"name\": \"河坊街\",\n          \"type\": \"attraction\",\n          \"description\": \"体验杭州夜市文化，品尝小吃，购买特色纪念品\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1582212779829-5f3e2a9b9e0d?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市上城区河坊街\"\n          },\n          \"estimatedCost\": 100,\n          \"tips\": [\"晚上6点后更热闹\", \"注意保管好随身物品\"]\n        }\n      ]\n    },\n    {\n      \"day\": 2,\n      \"date\": \"2024-01-02\",\n      \"activities\": [\n        {\n          \"time\": \"morning\",\n          \"name\": \"灵隐寺\",\n          \"type\": \"attraction\",\n          \"description\": \"参观千年古刹，感受佛教文化，登飞来峰\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1588045538788-6c2c8b4e4f1a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市西湖区灵隐路法云弄1号\"\n          },\n          \"estimatedCost\": 80,\n          \"tips\": [\"建议穿舒适的鞋子\", \"可请导游讲解历史\"]\n        },\n        {\n          \"time\": \"noon\",\n          \"name\": \"知味观\",\n          \"type\": \"meal\",\n          \"description\": \"品尝杭州传统小吃，推荐猫耳朵、片儿川\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市上城区仁和路83号\"\n          },\n          \"estimatedCost\": 100,\n          \"tips\": [\"中午12点前就餐更安静\", \"可尝试特色甜品\"]\n        },\n        {\n          \"time\": \"evening\",\n          \"name\": \"西湖音乐喷泉\",\n          \"type\": \"attraction\",\n          \"description\": \"欣赏西湖边的音乐喷泉表演，感受光影艺术\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1582212779829-5f3e2a9b9e0d?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市西湖区湖滨路\"\n          },\n          \"estimatedCost\": 0,\n          \"tips\": [\"晚上7点和8点各有一场\", \"提前30分钟到场占位\"]\n        }\n      ]\n    },\n    {\n      \"day\": 3,\n      \"date\": \"2024-01-03\",\n      \"activities\": [\n        {\n          \"time\": \"morning\",\n          \"name\": \"龙井村\",\n          \"type\": \"attraction\",\n          \"description\": \"游览龙井茶园，体验采茶、品茶\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1588045538788-6c2c8b4e4f1a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市西湖区龙井路\"\n          },\n          \"estimatedCost\": 50,\n          \"tips\": [\"可预约茶艺体验\", \"记得带水杯\"]\n        },\n        {\n          \"time\": \"noon\",\n          \"name\": \"绿茶餐厅\",\n          \"type\": \"meal\",\n          \"description\": \"享受融合杭帮菜与现代创意菜的用餐体验\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=1470&q=80\",\n          \"location\": {\n            \"address\": \"杭州市西湖区文三路555号\"\n          },\n          \"estimatedCost\": 150,\n          \"tips\": [\"可提前网上预订\", \"环境优雅，适合拍照\"]\n        },\n        {\n          \"time\": \"evening\",\n          \"name\": \"宋城\",\n          \"type\": \"attraction\",\n          \"description\": \"观看《宋城千古情》表演，体验宋代文化\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1582212779829-5f3e2a9b9e0d?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=',NULL,37950,'2026-03-29 20:44:48',0),(2038235927827730433,2038235767332687874,'assistant','观察: 为您规划了3天2晚的轻松游行程，覆盖杭州主要景点，早中晚各安排1个景点，含住宿与餐饮建议，预算约2000元，适合休闲度假。\n\n```json\n{\n  \"destination\": \"杭州\",\n  \"days\": 3,\n  \"budget\": 2000,\n  \"theme\": \"轻松休闲游\",\n  \"dailyPlans\": [\n    {\n      \"day\": 1,\n      \"date\": \"2024-01-01\",\n      \"activities\": [\n        {\n          \"time\": \"morning\",\n          \"name\": \"