"estimatedCost\": 30,\n          \"tips\": [\"建议租用园内电瓶车节省体力\"]\n        },\n        {\n          \"time\": \"noon\",\n          \"name\": \"北京烤鸭\",\n          \"type\": \"meal\",\n          \"description\": \"品尝北京烤鸭，推荐全聚德或便宜坊。\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1513104890138-7c749659a591\",\n          \"location\": {\n            \"address\": \"北京市前门大街全聚德总店\"\n          },\n          \"estimatedCost\": 250,\n          \"tips\": [\"建议提前预订，控制人均预算120-300元\"]\n        },\n        {\n          \"time\": \"evening\",\n          \"name\": \"南锣鼓巷\",\n          \"type\": \"attraction\",\n          \"description\": \"漫步北京最古老的街区，体验胡同文化。\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1559503375-8a3e5a5d7c7a\",\n          \"location\": {\n            \"address\": \"北京市东城区南锣鼓巷\"\n          },\n          \"estimatedCost\": 0,\n          \"tips\": [\"可品尝各种网红小吃和饮品\"]\n        }\n      ]\n    },\n    {\n      \"day\": 3,\n      \"date\": \"第3天\",\n      \"transportAdvice\": \"地铁1号线/2号线前往天坛，约20分钟；步行游览南池子大街。\",\n      \"activities\": [\n        {\n          \"time\": \"morning\",\n          \"name\": \"天坛\",\n          \"type\": \"attraction\",\n          \"description\": \"参观祈年殿，了解古代祭天文化。\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1559503375-8a3e5a5d7c7a\",\n          \"location\": {\n            \"address\": \"北京市东城区天坛东路\"\n          },\n          \"estimatedCost\": 30,\n          \"tips\": [\"建议参观祈年殿和回音壁\"]\n        },\n        {\n          \"time\": \"noon\",\n          \"name\": \"南池子大街\",\n          \"type\": \"attraction\",\n          \"description\": \"漫步老北京胡同，体验传统四合院文化。\",\n          \"imageUrl\": \"https://images.unsplash.com/photo-1559503375-8a3e5a5d7c7a\",\n          \"location\": {\n            \"address\": \"北京市东城区南池子大街\"\n          },\n          \"estimatedCost\": 0,\n          \"tips\": [\"可参观菊儿胡同等历史文化保护区\"]\n        },\n        {\n          \"time\": \"evening\",\n          \"name\": \"三里屯\",\n         