--
-- Table structure for table `knowledge_attraction`
--

DROP TABLE IF EXISTS `knowledge_attraction`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_attraction` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(128) NOT NULL COMMENT '景点名称',
  `description` text COMMENT '景点描述',
  `category` varchar(64) DEFAULT NULL COMMENT '类型：自然/文化/温泉/美食/休闲',
  `season` varchar(32) DEFAULT NULL COMMENT '最佳季节：春/夏/秋/冬/全年',
  `suitable_for` varchar(64) DEFAULT NULL COMMENT '适合人群：家庭/情侣/老人/儿童/年轻人',
  `price_level` int DEFAULT NULL COMMENT '价格等级：1-5',
  `rating` double DEFAULT NULL COMMENT '评分（0-5）',
  `tags` json DEFAULT NULL COMMENT '标签JSON数组',
  `address` varchar(255) DEFAULT NULL COMMENT '地址',
  `opening_hours` varchar(128) DEFAULT NULL COMMENT '营业时间',
  `ticket_price` varchar(128) DEFAULT NULL COMMENT '门票价格',
  `features` json DEFAULT NULL COMMENT '特色亮点JSON数组',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`),
  KEY `idx_name` (`name`),
  KEY `idx_is_deleted` (`is_deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='景点知识库';
/*!40101 SET character_set_client = @saved_cs_client */;

