INSERT INTO `knowledge_attraction` VALUES (1,'西湖','杭州核心景区，适合环湖慢游与夜景打卡。','自然','全年','家庭/情侣/年轻人',2,4.9,'[\"杭州\", \"湖景\", \"城市名片\"]','浙江省杭州市西湖风景名胜区','全天开放','免费（部分景点收费）','[\"苏堤春晓\", \"断桥残雪\", \"环湖骑行\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(2,'灵隐寺','千年古刹，历史文化氛围浓厚。','文化','全年','家庭/老人/文化爱好者',3,4.8,'[\"杭州\", \"寺庙\", \"文化\"]','浙江省杭州市西湖区灵隐路法云弄1号','07:00-18:00','约45元','[\"飞来峰\", \"祈福\", \"古建筑\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(3,'西溪湿地','城市湿地公园，生态环境好，适合半日游。','自然','春/秋','家庭/情侣',3,4.7,'[\"杭州\", \"湿地\", \"生态\"]','浙江省杭州市西湖区天目山路518号','08:00-17:30','约80元','[\"摇橹船\", \"水上森林\", \"观鸟\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(4,'拙政园','苏州代表性古典园林，适合文化深度游。','文化','春/秋','家庭/情侣/文化爱好者',3,4.8,'[\"苏州\", \"园林\", \"世界文化遗产\"]','江苏省苏州市姑苏区东北街178号','07:30-17:30','约80元','[\"江南园林\", \"亭台楼阁\", \"摄影\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(5,'平江路','苏州古城水巷，夜景与小店体验感强。','休闲','全年','年轻人/情侣',2,4.6,'[\"苏州\", \"古街\", \"夜游\"]','江苏省苏州市姑苏区平江路','全天开放','免费','[\"小桥流水\", \"文艺店铺\", \"夜景散步\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(6,'兵马俑','世界级考古遗址，历史震撼感强。','文化','全年','家庭/文化爱好者',4,4.9,'[\"西安\", \"历史\", \"博物馆\"]','陕西省西安市临潼区秦陵北路','08:30-18:00','约120元','[\"秦代历史\", \"大型遗址\", \"讲解服务\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(7,'大雁塔','西安地标建筑，适合夜景和历史文化游。','文化','全年','家庭/情侣',3,4.7,'[\"西安\", \"地标\", \"唐文化\"]','陕西省西安市雁塔区雁塔路南段11号','08:00-22:00','登塔约30元','[\"音乐喷泉\", \"夜景灯光\", \"唐风街区\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(8,'宽窄巷子','成都人文休闲街区，适合美食与慢生活体验。','休闲','全年','年轻人/家庭',2,4.5,'[\"成都\", \"街区\", \"美食\"]','四川省成都市青羊区金河路口','全天开放','免费','[\"川西建筑\", \"茶馆体验\", \"伴手礼\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(9,'锦里古街','成都热门古街，夜间氛围浓厚。','休闲','全年','情侣/年轻人',2,4.5,'[\"成都\", \"古街\", \"夜市\"]','四川省成都市武侯区武侯祠大街231号附近','全天开放','免费','[\"夜景\", \"小吃密集\", \"民俗演出\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(10,'外滩','上海经典地标，适合夜景与城市风光。','休闲','全年','情侣/年轻人/家庭',2,4.8,'[\"上海\", \"地标\", \"夜景\"]','上海市黄浦区中山东一路','全天开放','免费','[\"万国建筑群\", \"浦江夜景\", \"步行观景\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(11,'豫园','上海历史园林，适合老城厢文化体验。','文化','全年','家庭/文化爱好者',3,4.6,'[\"上海\", \"园林\", \"老城厢\"]','上海市黄浦区福佑路168号','09:00-16:30','约40元','[\"江南园林\", \"城隍庙商圈\", \"传统建筑\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(12,'故宫','北京核心历史景区，文化信息量大。','文化','全年','家庭/文化爱好者',4,4.9,'[\"北京\", \"博物院\", \"历史\"]','北京市东城区景山前街4号','08:30-17:00','旺季约60元','[\"皇家建筑群\", \"中轴线\", \"珍贵文物\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0),(13,'颐和园','北京大型皇家园林，适合步行与乘船。','自然','春/秋','家庭/老人',3,4.8,'[\"北京\", \"园林\", \"皇家\"]','北京市海淀区新建宫门路19号','06:30-18:00','约30元','[\"昆明湖\", \"长廊\", \"皇家园林\"]','2026-03-30 15:04:01','2026-03-30 15:04:01',0);
