DROP TABLE IF EXISTS `knowledge_food`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge_food` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name` varchar(128) NOT NULL COMMENT '美食名称',
  `description` text COMMENT '美食描述',
  `category` varchar(64) DEFAULT NULL COMMENT '类型：主食/小吃/特产/饮品',
  `taste` varchar(64) DEFAULT NULL COMMENT '口味：甜/咸/辣/酸/鲜',
  `price_range` varchar(64) DEFAULT NULL COMMENT '价格区间',
  `where_to_eat` varchar(255) DEFAULT NULL COMMENT '推荐地点',
  `season` varchar(32) DEFAULT NULL COMMENT '最佳季节',
  `tags` json DEFAULT NULL COMMENT '标签JSON数组',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_deleted` tinyint NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`),
  KEY `idx_name` (`name`),
  KEY `idx_is_deleted` (`is_deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='美食知识库';
/*!40101 SET character_set_client = @saved_cs_client */;

