INSERT INTO `knowledge_food` VALUES (1,'西湖醋鱼','杭州代表性传统名菜，鱼肉鲜嫩，酸甜平衡。','主食','酸/鲜','50-120元','杭州楼外楼、知味观等杭帮菜馆','全年','[\"杭州\", \"杭帮菜\", \"经典\"]','2026-03-30 15:04:01',0),(2,'东坡肉','肥而不腻，入口即化，适合搭配米饭。','主食','咸/鲜','40-100元','杭州新白鹿、外婆家等杭帮餐厅','全年','[\"杭州\", \"杭帮菜\", \"红烧\"]','2026-03-30 15:04:01',0),(3,'龙井虾仁','清鲜爽口，茶香与虾仁风味结合。','主食','鲜','60-160元','杭州湖滨商圈、河坊街周边餐厅','春/夏','[\"杭州\", \"茶香\", \"清淡\"]','2026-03-30 15:04:01',0),(4,'苏式汤面','讲究汤底与浇头，口感清爽。','主食','咸/鲜','15-40元','苏州观前街、十全街面馆','全年','[\"苏州\", \"面食\", \"本地早餐\"]','2026-03-30 15:04:01',0),(5,'松鼠桂鱼','苏帮菜经典，外酥里嫩，酸甜开胃。','主食','甜/酸','80-180元','苏州老字号苏帮菜馆','全年','[\"苏州\", \"苏帮菜\", \"宴请\"]','2026-03-30 15:04:01',0),(6,'肉夹馍','西安地道小吃，外酥内香。','小吃','咸/鲜','8-20元','西安回民街、钟楼周边小吃店','全年','[\"西安\", \"小吃\", \"便捷\"]','2026-03-30 15:04:01',0),(7,'羊肉泡馍','陕西特色，汤浓肉香，饱腹感强。','主食','咸/鲜','25-50元','西安回民街、永兴坊','秋/冬','[\"西安\", \"陕西菜\", \"暖胃\"]','2026-03-30 15:04:01',0),(8,'夫妻肺片','成都冷菜代表，麻辣鲜香。','小吃','辣/鲜','20-50元','成都春熙路、锦里周边川菜馆','全年','[\"成都\", \"川菜\", \"麻辣\"]','2026-03-30 15:04:01',0),(9,'钟水饺','甜辣微麻，风味鲜明。','小吃','辣/甜','15-35元','成都建设路、宽窄巷子附近小吃店','全年','[\"成都\", \"小吃\", \"川味\"]','2026-03-30 15:04:01',0),(10,'小笼包','上海经典点心，汤汁丰富。','小吃','鲜','12-40元','上海城隍庙、豫园周边点心店','全年','[\"上海\", \"点心\", \"早餐\"]','2026-03-30 15:04:01',0),(11,'生煎包','底脆汁多，口感层次丰富。','小吃','咸/鲜','8-25元','上海黄河路、南京西路附近小店','全年','[\"上海\", \"街头小吃\", \"热门\"]','2026-03-30 15:04:01',0),(12,'北京烤鸭','北京代表性名菜，皮脆肉嫩。','主食','咸/鲜','120-300元','北京全聚德、便宜坊等老字号','全年','[\"北京\", \"名菜\", \"宴请\"]','2026-03-30 15:04:01',0),(13,'炸酱面','北京家常主食，酱香浓郁。','主食','咸/鲜','20-45元','北京前门、鼓楼周边面馆','全年','[\"北京\", \"面食\", \"家常\"]','2026-03-30 15:04:01',0);
