INSERT INTO `product` VALUES (34,2037451929249677314,'潮汕牛肉火锅双人套餐','汕头','汕头市龙湖区长平路95号','[\"美食\",\"牛肉火锅\",\"招牌\"]','精选吊龙、嫩肉、匙柄与手打牛肉丸，适合第一次来潮汕的游客直接体验代表性风味。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_cGDWzQyO3kIdeoOI.webp',23.3623050,116.7096700,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(35,2037451929249677314,'汕头蚝烙体验套餐','汕头','汕头市金平区安平路1号','[\"美食\",\"小吃\",\"蚝烙\"]','外脆内嫩的潮汕经典小吃，适合作为老城区逛吃路线中的高频推荐。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_jW3VzfMnH2MV3BH0.webp',23.3552720,116.6742460,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(36,2037451929249677314,'小公园卤鹅切盘','汕头','汕头市金平区镇邦路62号','[\"美食\",\"卤味\",\"本地老店\"]','偏甜鲜风味的潮汕卤鹅，是汕头老店路线里很稳的一道招牌熟食。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_QhTa1jduIqFN3itu.webp',23.3503070,116.6695180,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(37,2037451929249677314,'汕头生腌拼盘','汕头','汕头市龙湖区珠江路46号','[\"美食\",\"海鲜\",\"生腌\"]','集合虾姑、花螺等潮汕生腌风味，适合喜欢鲜味和夜生活体验的游客。',1,0,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_OpGEhmKnasLn9z6F.webp',23.3772360,116.7443620,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(38,2037451929249677314,'南澳海鲜大排档双人餐','汕头','广东省汕头市南澳县后宅镇海滨路12号','[\"海鲜\",\"海岛\",\"美食\"]','适合南澳岛自驾或海边慢游时安排一顿现捞现做海鲜正餐。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_S71ef0ausrKbTu7g.webp',23.4146420,117.0317270,'2026-04-15 13:09:52','2026-04-15 13:30:54',0),(39,2037451929249677314,'牌坊街腐乳饼手信礼盒','潮州','广东省潮州市湘桥区太平街道牌坊街139号','[\"伴手礼\",\"传统糕点\",\"腐乳饼\"]','潮州古城代表性手信之一，饼皮酥香、内馅层次丰富，适合返程购买。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_0k8TSiRIJeSGyj6p.webp',23.6686460,116.6507900,'2026-04-15 13:09:52','2026-04-15 13:30:54',0),(40,2037451929249677314,'潮州工夫茶体验套装','潮州','广东省潮州市湘桥区西马路3号','[\"茶饮\",\"工夫茶\",\"文化体验\"]','适合搭配古城慢游，既可以现场体验，也适合作为地方文化伴手礼。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_go7W20Px5pqaN4Qe.webp',23.6632450,116.6478110,'2026-04-15 13:09:52','2026-04-15 13:30:54',0),(41,2037451929249677314,'潮州粿条卷双拼','潮州','广东省潮州市湘桥区开元路开元寺附近','[\"美食\",\"粿品\",\"早餐\"]','米香明显、口感柔韧，适合放进潮州半日老城步行线中的早餐推荐。',1,0,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_oVVBIlI0rBeK38YO.webp',23.6630560,116.6489630,'2026-04-15 13:09:52','2026-04-15 13:32:04',0),(42,2037451929249677314,'潮州鸭母捻甜品碗','潮州','广东省潮州市湘桥区牌坊街载阳茶馆附近','[\"甜品\",\"鸭母捻\",\"夜宵\"]','适合古城夜游后的收尾甜品，兼顾在地特色和游客接受度。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_Hs5JfhYXybFygYse.webp',23.6660920,116.6501600,'2026-04-15 13:09:52','2026-04-15 13:32:04',0),(43,2037451929249677314,'潮州卤水拼盘','潮州','广东省潮州市湘桥区西湖公园附近','[\"美食\",\"卤味\",\"本地特色\"]','集合鹅肉、豆干、卤蛋等经典潮州卤味，适合多人分享。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_9iwV9BLMwo8Md1U5.webp',23.6710220,116.6444140,'2026-04-15 13:09:52','2026-04-15 13:32:04',0),(44,2037451929249677314,'揭阳普宁豆干礼盒','揭阳','广东省揭阳市普宁市普宁国际商品城附近','[\"伴手礼\",\"豆制品\",\"普宁豆干\"]','揭阳代表性地方特产，适合自驾返程或带回家做二次料理。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_td36z7wkN2hUS1Xm.webp',23.2939380,116.1924590,'2026-04-15 13:09:52','2026-04-15 13:34:07',0),(45,2037451929249677314,'揭阳粿汁套餐','揭阳','广东省揭阳市榕城区进贤门城楼南侧','[\"美食\",\"粿汁\",\"本地早餐\"]','咸香浓郁、搭配卤料丰富，适合作为揭阳本地早餐线中的核心推荐。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_NvvxrnZ2ydRo87i2.webp',23.5349180,116.3578220,'2026-04-15 13:09:52','2026-04-15 13:34:07',0),(46,2037451929249677314,'揭阳乒乓粿组合','揭阳','广东省揭阳市榕城区进贤门步行街西段','[\"小吃\",\"乒乓粿\",\"本地特色\"]','适合作为揭阳街巷漫游中的边走边吃选择，软糯外皮搭配咸香馅料辨识度很高。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_u1rDIoEQX30fipQZ.webp',23.5345470,116.3561330,'2026-04-15 13:09:52','2026-04-15 13:34:07',0),(47,2037451929249677314,'普宁炸豆干双人份','揭阳','广东省揭阳市普宁市万泰汇购物中心附近','[\"美食\",\"普宁\",\"炸豆干\"]','外酥里嫩，蘸料突出潮汕风味，适合夜宵或小吃线路推荐。',1,1,'https://via.placeholder.com/800x600?text=Chaoshan+Food',23.3124890,116.1624310,'2026-04-15 13:09:52','2026-04-15 21:52:30',1),(48,2037451929249677314,'揭阳隆江猪脚饭套餐','揭阳','广东省揭阳市榕城区黄岐山森林公园附近','[\"美食\",\"快餐\",\"猪脚饭\"]','经典潮汕高频简餐，适合旅途中快速解决正餐需求。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_eplk2vfrsqzxnJ93.webp',23.5824510,116.3725860,'2026-04-15 13:09:52','2026-04-15 13:32:04',0),(49,2037451929249677314,'潮汕手打牛肉丸冷链礼盒','潮汕','汕头市龙湖区黄山路65号','[\"伴手礼\",\"牛肉丸\",\"冷链\"]','适合作为返程手信，口感弹牙，复热后仍能保留潮汕街头牛肉丸汤风味。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_TiOBA90Xwf22pbaT.webp',23.3741530,116.7474230,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(50,2037451929249677314,'潮汕砂锅粥双人餐','潮汕','汕头市龙湖区韩江路37号','[\"美食\",\"砂锅粥\",\"夜宵\"]','米粒绵密、海鲜鲜甜，适合晚间收尾或雨天行程中的暖胃选择。',1,1,'https://qq-1375584552.cos.ap-guangzhou.myqcloud.com/product_cover/2026-04-15_ZWukXXKU5G73X6nn.webp',23.3569960,116.7446500,'2026-04-15 13:09:52','2026-04-15 13:28:30',0),(51,2037451929249677314,'潮汕工夫茶伴手礼盒','潮汕','潮州市湘桥区意东一路20号','[\"伴手礼\",\"茶饮\",\"工夫茶\"]','兼具文化属性与携带便利性，适合作为送礼或返程采购。',1,1,'https://via.placeholder.com/800x600?text=Chaoshan+Food',23.6852990,116.6580390,'2026-04-15 13:09:52','2026-04-15 21:52:37',1),(52,2044647999385972738,'测试潮汕牛肉丸','潮州','广东省潮州市湘桥区西马路1号','[\"美食\",\"推荐\"]','接口测试商品',1,1,'https://example.com/product.jpg',23.6640700,116.6496800,'2026-04-16 13:24:07','2026-04-16 13:24:07',0),(53,2044648500609495041,'性能测试商品','杭州','浙江省杭州市西湖区龙井路1号','[\"性能\"]','性能测试',1,1,'https://example.com/perf.jpg',30.2518640,120.1369640,'2026-04-16 13:26:05','2026-04-16 13:26:05',0),(54,2044648629336879106,'性能测试商品','杭州','浙江省杭州市西湖区龙井路1号','[\"性能\"]','性能测试',1,1,'https://example.com/perf.jpg',30.2518640,120.1369640,'2026-04-16 13:26:36','2026-04-16 13:26:36',0);
