--
-- Table structure for table `trip`
--

DROP TABLE IF EXISTS `trip`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `trip` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `destination` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '目的地',
  `days` int NOT NULL COMMENT '天数',
  `budget` int DEFAULT NULL COMMENT '预算（元）',
  `theme` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '主题（如：休闲、探险、文化等）',
  `start_date` datetime DEFAULT NULL COMMENT '开始日期',
  `end_date` datetime DEFAULT NULL COMMENT '结束日期',
  `daily_highlights` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '按天亮点（JSON格式）',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'draft' COMMENT '状态：draft（草稿）、accepted（已接受）、completed（已完成）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_delete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除（0-未删除，1-已删除）',
  `structured_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '完整结构化数据（JSON格式）',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_user_id` (`user_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_create_time` (`create_time`) USING BTREE,
  KEY `idx_is_delete` (`is_delete`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='行程表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `trip`
--

LOCK TABLES `trip` WRITE;
/*!40000 ALTER TABLE `trip` DISABLE KEYS */;
INSERT INTO `trip` VALUES (17,2037451929249677314,'揭阳',3,1000,'市区探索与文化体验',NULL,NULL,'{\"1\":[\"morning 揭阳学宫：揭阳历史文化地标，了解潮汕文化与古建筑。\",\"noon 午餐·潮汕牛肉火锅：品尝当地特色潮汕牛肉火锅，推荐新鲜部位。\",\"evening 进贤门广场夜景：市区夜景地标，适合散步与拍照。\"],\"2\":[\"morning 揭阳市博物馆：了解揭阳历史与民俗文化，常设展丰富。\",\"noon 午餐·潮汕小吃拼盘：品尝蚝烙、肠粉、咸水粿等经典潮汕小吃。\",\"evening 榕江夜游：乘船游览榕江两岸夜景，感受水城风光。\"],\"3\":[\"morning 黄岐山风景区：市区近郊山林公园，适合徒步与观景。\",\"noon 午餐·揭阳特色菜：尝试普宁豆干、菜脯蛋等本地特色菜。\",\"evening 市区购物与自由活动：在市区商圈自由购物或品尝夜市小吃。\"]}','planned','2026-04-15 21:55:08','2026-04-15 21:55:08',0,'{\"destination\":\"揭阳\",\"days\":3,\"budget\":1000,\"theme\":\"市区探索与文化体验\",\"dailyPlans\":[{\"day\":1,\"date\":\"2026-04-15\",\"activities\":[{\"time\":\"morning\",\"name\":\"揭阳学宫\",\"type\":\"attraction\",\"description\":\"揭阳历史文化地标，了解潮汕文化与古建筑。\",\"imageUrl\":\"https://images.pexels.com/photos/33996096/pexels-photo-33996096.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区韩祠路\",\"latitude\":23.532211,\"longitude\":116.388747,\"coordinates\":[116.388747,23.532211]},\"estimatedCost\":20,\"tips\":[\"开放时间待确认\",\"建议上午参观避免人流高峰\"]},{\"time\":\"noon\",\"name\":\"午餐·潮汕牛肉火锅\",\"type\":\"meal\",\"description\":\"品尝当地特色潮汕牛肉火锅，推荐新鲜部位。\",\"imageUrl\":\"https://images.pexels.com/photos/19199226/pexels-photo-19199226.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区新兴东路\",\"latitude\":23.535213,\"longitude\":116.392244,\"coordinates\":[116.392244,23.535213]},\"estimatedCost\":80,\"tips\":[\"提前到店，避免排队\"]},{\"time\":\"evening\",\"name\":\"进贤门广场夜景\",\"type\":\"attraction\",\"description\":\"市区夜景地标，适合散步与拍照。\",\"imageUrl\":\"https://images.pexels.com/photos/36286022/pexels-photo-36286022.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区进贤门大道\",\"latitude\":23.531234,\"longitude\":116.385678,\"coordinates\":[116.385678,23.531234]},\"estimatedCost\":0,\"tips\":[\"傍晚前往，光线最佳\"]}]},{\"day\":2,\"date\":\"2026-04-16\",\"activities\":[{\"time\":\"morning\",\"name\":\"揭阳市博物馆\",\"type\":\"attraction\",\"description\":\"了解揭阳历史与民俗文化，常设展丰富。\",\"imageUrl\":\"https://images.pexels.com/photos/35416960/pexels-photo-35416960.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区临江北路\",\"latitude\":23.533456,\"longitude\":116.382111,\"coordinates\":[116.382111,23.533456]},\"estimatedCost\":15,\"tips\":[\"开放时间待确认\",\"建议带水与轻食\"]},{\"time\":\"noon\",\"name\":\"午餐·潮汕小吃拼盘\",\"type\":\"meal\",\"description\":\"品尝蚝烙、肠粉、咸水粿等经典潮汕小吃。\",\"imageUrl\":\"https://images.pexels.com/photos/32301763/pexels-photo-32301763.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区中山路\",\"latitude\":23.534444,\"longitude\":116.389999,\"coordinates\":[116.389999,23.534444]},\"estimatedCost\":50,\"tips\":[\"选择口碑老店，排队可接受\"]},{\"time\":\"evening\",\"name\":\"榕江夜游\",\"type\":\"attraction\",\"description\":\"乘船游览榕江两岸夜景，感受水城风光。\",\"imageUrl\":\"https://images.pexels.com/photos/9152306/pexels-photo-9152306.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区滨江长廊\",\"latitude\":23.536666,\"longitude\":116.388888,\"coordinates\":[116.388888,23.536666]},\"estimatedCost\":60,\"tips\":[\"提前预订船票\",\"注意天气变化\"]}]},{\"day\":3,\"date\":\"2026-04-17\",\"activities\":[{\"time\":\"morning\",\"name\":\"黄岐山风景区\",\"type\":\"attraction\",\"description\":\"市区近郊山林公园，适合徒步与观景。\",\"imageUrl\":\"https://images.pexels.com/photos/31829081/pexels-photo-31829081.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区黄岐山大道\",\"latitude\":23.544444,\"longitude\":116.366666,\"coordinates\":[116.366666,23.544444]},\"estimatedCost\":20,\"tips\":[\"携带雨具，天气预报有雷阵雨\",\"穿舒适的徒步鞋\"]},{\"time\":\"noon\",\"name\":\"午餐·揭阳特色菜\",\"type\":\"meal\",\"description\":\"尝试普宁豆干、菜脯蛋等本地特色菜。\",\"imageUrl\":\"https://images.pexels.com/photos/36466075/pexels-photo-36466075.jpeg?auto=compress&cs=tinysrgb&fit=crop&h=627&w=1200\",\"location\":{\"address\":\"广东省揭阳市榕城区天福路\",\"latitu